const CSS_SRC="@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700;800;900&display=swap');\n@tailwind base;\n@tailwind components;\n@tailwind utilities;\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   TRENGO \u2014 Ultra Premium design system (Facebook format)\n   Blanc \u00b7 Bleu Facebook \u00b7 Jaune \u00b7 Noir \u00b7 Rose cristal \u00b7\n   Dor\u00e9 brillant \u00b7 Argent\u00e9 brillant \u00b7 Orange\n   \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n:root {\n  --blue:        #1877F2;   /* Bleu Facebook */\n  --blue-dark:   #0E5FCB;\n  --blue-pale:   #E7F0FE;\n  --yellow:      #F2B300;   /* Dor\u00e9 (logo) */\n  --orange:      #F2B300;   /* Dor\u00e9 (logo) */\n  --black:       #050505;   /* Noir Facebook */\n  --gray-txt:    #65676B;\n  --pink:        #FF2D8D;   /* Rose cristal */\n  --pink-light:  #FF7AB8;\n  --pink-pale:   #FFE9F4;\n  --gold:        #F2B300;   /* Dor\u00e9 */\n  --gold-light:  #FFE066;\n  --silver:      #C7CCD6;   /* Argent\u00e9 */\n  --silver-light:#F2F4F8;\n  --white:       #FFFFFF;\n  --canvas:      #F0F2F5;   /* Fond gris FB tr\u00e8s clair sur desktop */\n  --line:        #E4E6EB;\n\n  /* Aliases h\u00e9rit\u00e9s (anciens noms utilis\u00e9s dans le code) */\n  --rose:       var(--pink);\n  --rose-light: var(--pink-light);\n  --rose-pale:  var(--pink-pale);\n  --gray-50:  #FFFFFF;\n  --gray-100: #F0F2F5;\n  --gray-200: #E4E6EB;\n  --gray-400: #8A8D91;\n  --gray-600: #65676B;\n  --gray-800: #3A3B3C;\n  --gray-900: #050505;\n}\n\n* { box-sizing: border-box; margin: 0; padding: 0; }\n\nhtml {\n  overscroll-behavior-y: contain;   /* desactive le \"glow\" natif Android -> laisse notre pull-to-refresh JS gerer le geste */\n}\n\nbody {\n  font-family: 'Poppins', sans-serif;\n  background: var(--white);      /* fond blanc demand\u00e9 */\n  color: var(--black);\n  min-height: 100vh;\n  overscroll-behavior-y: contain;\n  touch-action: pan-y pan-x;\n}\n\n/* \u2500\u2500 Dark mode (conserv\u00e9) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500 */\n.dark body, .dark { background: #0B0D12 !important; color: #E7EAF0 !important; }\n.dark .card, .dark .card-fb { background: #15181F !important; border-color: #232733 !important; color: #E7EAF0 !important; }\n.dark .card p, .dark .card span, .dark .card div,\n.dark p, .dark span, .dark div, .dark h1, .dark h2, .dark h3 { color: #E7EAF0; }\n.dark .input { background: #1C2028 !important; color: #E7EAF0 !important; border-color: #2C3140 !important; }\n.dark .input::placeholder { color: #6E7686 !important; }\n.dark .navbar { background: #15181F !important; border-color: #232733 !important; }\n.dark .nav-item { color: #8A93A6 !important; }\n.dark .nav-item.active, .dark .nav-item.active span { color: var(--blue) !important; }\n.dark .msg-bubble-other { background: #232733; color: #E7EAF0 !important; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 BOUTONS \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n\n/* Bouton principal \u2014 ROSE CRISTAL brillant */\n.btn-primary {\n  position: relative;\n  background: linear-gradient(135deg, #FF2D8D 0%, #FF5EA8 45%, #FF8FC6 100%);\n  color: white;\n  border: 1px solid rgba(255,255,255,0.55);\n  padding: 10px 20px;\n  border-radius: 25px;\n  font-weight: 700;\n  cursor: pointer;\n  transition: all .25s ease;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 4px 18px rgba(255,45,141,.45), inset 0 1px 0 rgba(255,255,255,.6), inset 0 -2px 6px rgba(180,0,90,.25);\n  overflow: hidden;\n}\n.btn-primary::after {              /* reflet cristal */\n  content: '';\n  position: absolute; top: 0; left: -80%;\n  width: 55%; height: 100%;\n  background: linear-gradient(105deg, transparent, rgba(255,255,255,.65), transparent);\n  transform: skewX(-20deg);\n  animation: crystalSweep 3.2s ease-in-out infinite;\n}\n.btn-primary:hover { transform: translateY(-2px); box-shadow: 0 8px 26px rgba(255,45,141,.6), inset 0 1px 0 rgba(255,255,255,.7); }\n.btn-primary:disabled { opacity: .55; }\n\n/* Bouton bleu Facebook */\n.btn-blue {\n  background: linear-gradient(180deg, #1B84FF, #1877F2);\n  color: white; border: none;\n  padding: 10px 20px; border-radius: 10px;\n  font-weight: 700; cursor: pointer;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 3px 12px rgba(24,119,242,.35);\n  transition: all .2s ease;\n}\n.btn-blue:hover { background: var(--blue-dark); transform: translateY(-1px); }\n\n/* Bouton secondaire \u2014 ARGENT\u00c9 brillant */\n.btn-secondary {\n  position: relative;\n  background: linear-gradient(135deg, #FDFEFF 0%, #DDE2EC 40%, #C7CCD6 60%, #F2F4F8 100%);\n  background-size: 220% 220%;\n  animation: metalShine 4.5s ease infinite;\n  color: #2B2F38;\n  border: 1px solid #C4CAD6;\n  padding: 8px 18px;\n  border-radius: 25px;\n  font-weight: 600; cursor: pointer;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 2px 10px rgba(120,130,150,.3), inset 0 1px 0 rgba(255,255,255,.9);\n  transition: all .25s ease;\n}\n.btn-secondary:hover { transform: translateY(-1px); box-shadow: 0 5px 16px rgba(120,130,150,.4); }\n\n/* Bouton DOR\u00c9 brillant */\n.btn-gold {\n  position: relative;\n  background: linear-gradient(135deg, #FFE066 0%, #F2B300 40%, #D99A00 60%, #FFD84D 100%);\n  background-size: 220% 220%;\n  animation: metalShine 4s ease infinite;\n  color: #4A3400;\n  border: 1px solid #E8B400;\n  padding: 8px 18px; border-radius: 25px;\n  font-weight: 700; cursor: pointer;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 3px 14px rgba(242,179,0,.45), inset 0 1px 0 rgba(255,255,255,.7);\n  transition: all .25s ease;\n}\n.btn-gold:hover { transform: translateY(-1px); box-shadow: 0 6px 20px rgba(242,179,0,.6); }\n\n/* Bouton orange */\n.btn-orange {\n  background: linear-gradient(135deg, #FFD84D, #F2B300);\n  color: #4A3400;\n  border: none;\n  padding: 8px 18px; border-radius: 25px;\n  font-weight: 700; cursor: pointer;\n  font-family: 'Poppins', sans-serif;\n  box-shadow: 0 3px 14px rgba(242,179,0,.4);\n  transition: all .2s ease;\n}\n.btn-orange:hover { transform: translateY(-1px); }\n\n@keyframes crystalSweep {\n  0%   { left: -80%; }\n  55%  { left: 130%; }\n  100% { left: 130%; }\n}\n@keyframes metalShine {\n  0%   { background-position: 0% 50%; }\n  50%  { background-position: 100% 50%; }\n  100% { background-position: 0% 50%; }\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 CARTES \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.card {\n  background: white;\n  border-radius: 12px;\n  box-shadow: 0 1px 2px rgba(0,0,0,.1), 0 2px 12px rgba(24,119,242,.05);\n  border: 1px solid var(--line);\n}\n.card-fb {\n  background: white;\n  border-radius: 8px;\n  box-shadow: 0 1px 3px rgba(0,0,0,.12);\n  margin-bottom: 8px;\n  overflow: hidden;\n}\n\n/* Publications pleine largeur (format Facebook mobile) */\n.post-card {\n  border-radius: 0;\n  border-left: none;\n  border-right: none;\n  margin-bottom: 8px;\n  overflow: visible;\n  transition: box-shadow .2s;\n  width: 100%;\n}\n@media (min-width: 700px) {\n  .post-card { border-radius: 12px; border: 1px solid var(--line); }\n}\n.post-card:hover { box-shadow: 0 4px 20px rgba(24,119,242,.1); }\n.post-content-click { cursor: pointer; }\n\n/* M\u00e9dia pleine largeur, bord \u00e0 bord comme Facebook */\n.post-media-full { margin: 8px -16px 0; width: calc(100% + 32px); }\n.post-media-full img, .post-media-full video { width: 100%; display: block; border-radius: 0; }\n\n.input {\n  background: var(--canvas);\n  border: 1.5px solid var(--line);\n  border-radius: 20px;\n  padding: 10px 14px;\n  font-family: 'Poppins', sans-serif;\n  font-size: 14px;\n  color: var(--black);\n  transition: border-color .2s;\n  width: 100%;\n}\n.input:focus { outline: none; border-color: var(--blue); box-shadow: 0 0 0 3px rgba(24,119,242,.12); }\ninput::placeholder, textarea::placeholder { color: #8A8D91 !important; font-size: 13px; }\n.textbg-textarea::placeholder { color: rgba(255,255,255,0.65) !important; font-size: 22px; }\n\n/* Scrollbar */\n::-webkit-scrollbar { width: 5px; height: 5px; }\n::-webkit-scrollbar-track { background: transparent; }\n::-webkit-scrollbar-thumb { background: var(--silver); border-radius: 10px; }\n::-webkit-scrollbar-thumb:hover { background: var(--blue); }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 ANIMATIONS \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n@keyframes fadeIn  { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }\n@keyframes slideIn { from { opacity: 0; transform: translateX(-20px); } to { opacity: 1; transform: translateX(0); } }\n@keyframes pulse-blue { 0%,100% { box-shadow: 0 0 0 0 rgba(24,119,242,.4); } 50% { box-shadow: 0 0 0 8px rgba(24,119,242,0); } }\n.animate-fade  { animation: fadeIn .3s ease; }\n.animate-slide { animation: slideIn .3s ease; }\n.pulse-dot     { animation: pulse-blue 2s infinite; }\n\n/* Logo \u2014 halo DOR\u00c9 brillant */\n@keyframes logoShimmer {\n  0%   { filter: brightness(1)   drop-shadow(0 0 0px  #F2B300); }\n  50%  { filter: brightness(1.35) drop-shadow(0 0 14px #FFD84D) drop-shadow(0 0 28px rgba(24,119,242,.55)); }\n  100% { filter: brightness(1)   drop-shadow(0 0 0px  #F2B300); }\n}\n.logo-shimmer { animation: logoShimmer 2.4s ease-in-out infinite; }\n\n/* Texte dor\u00e9 brillant (nom de l'app) */\n.text-gold-shine {\n  background: linear-gradient(90deg, #B8860B, #FFD84D 30%, #F2B300 50%, #FFF2B0 70%, #B8860B);\n  background-size: 250% auto;\n  -webkit-background-clip: text; background-clip: text;\n  -webkit-text-fill-color: transparent; color: transparent;\n  animation: goldFlow 3.5s linear infinite;\n}\n@keyframes goldFlow { to { background-position: 250% center; } }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 BADGES \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.notif-badge {\n  background: #FF1744; color: white; border-radius: 9px;\n  min-width: 17px; height: 17px; padding: 0 4px; font-size: 9px; font-weight: 700;\n  display: flex; align-items: center; justify-content: center;\n  position: absolute; top: -5px; right: -6px;\n  border: 2px solid white; box-sizing: border-box;\n  line-height: 1; z-index: 5; pointer-events: none;\n  box-shadow: 0 1px 3px rgba(0,0,0,.25);\n}\n.dark .notif-badge { border-color: #15181F; }\n.avatar { border-radius: 50%; object-fit: cover; border: 2px solid var(--line); }\n.avatar-ring { border: 2px solid var(--blue); }\n\n.sale-badge {\n  background: linear-gradient(135deg, #FFE066, #F2B300);\n  color: #4A3400; border-radius: 20px; padding: 4px 12px;\n  font-size: 12px; font-weight: 800;\n  box-shadow: 0 2px 8px rgba(242,179,0,.4);\n}\n.price-tag { color: var(--pink); font-weight: 800; font-size: 18px; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 MESSAGES (Messenger) \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.msg-bubble-me {\n  background: linear-gradient(135deg, #1B84FF, #1877F2);\n  color: white;\n  border-radius: 18px 18px 4px 18px;\n  padding: 10px 14px; max-width: 100%;\n  word-break: break-word; white-space: pre-wrap;\n  line-height: 1.5; font-size: 15px;\n}\n.msg-bubble-other {\n  background: var(--canvas); color: var(--black);\n  border-radius: 18px 18px 18px 4px;\n  padding: 10px 14px; max-width: 100%;\n  word-break: break-word; white-space: pre-wrap;\n  line-height: 1.5; font-size: 15px;\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 DOCK FLOTTANT (style Telegram) \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.floating-dock {\n  position: fixed;\n  left: 12px; right: 12px; bottom: 12px;\n  z-index: 100;\n  display: flex;\n  padding: 8px 6px;\n  background: rgba(255,255,255,.92);\n  backdrop-filter: blur(18px);\n  -webkit-backdrop-filter: blur(18px);\n  border: 1px solid rgba(228,230,235,.9);\n  border-radius: 26px;\n  box-shadow: 0 10px 34px rgba(5,5,5,.18), 0 2px 8px rgba(24,119,242,.12), inset 0 1px 0 rgba(255,255,255,.9);\n  max-width: 560px;\n  margin: 0 auto;\n}\n.dark .floating-dock { background: rgba(21,24,31,.92); border-color: #232733; }\n\n/* Animation \"emoji miakatra\" rehefa manao r\u00e9action amin'ny story (format Facebook) */\n.story-emoji-fly {\n  position: fixed; bottom: 90px; font-size: 32px; z-index: 320;\n  pointer-events: none; animation: emojiFly 1.2s ease-out forwards;\n}\n@keyframes emojiFly {\n  0%   { transform: translateY(0) scale(0.5); opacity: 0; }\n  15%  { transform: translateY(-20px) scale(1.3); opacity: 1; }\n  100% { transform: translateY(-220px) scale(1); opacity: 0; }\n}\n\n.dock-item {\n  flex: 1; display: flex; flex-direction: column; align-items: center;\n  gap: 2px; padding: 6px 2px;\n  background: none; border: none; cursor: pointer;\n  font-family: 'Poppins', sans-serif; font-size: 9.5px; font-weight: 500;\n  color: var(--gray-txt);\n  border-radius: 18px;\n  transition: transform .18s ease, background .18s ease;\n}\n.dock-item:active { transform: scale(.9); }\n@keyframes bellShake {\n  0%, 100% { transform: rotate(0deg); }\n  10%, 30% { transform: rotate(-14deg); }\n  20%, 40% { transform: rotate(14deg); }\n  50% { transform: rotate(-8deg); }\n  60% { transform: rotate(8deg); }\n  70% { transform: rotate(0deg); }\n}\n.bell-shake { animation: bellShake 0.7s ease-in-out; animation-iteration-count: 3; }\n\n.dock-icon {\n  width: 40px; height: 40px; border-radius: 14px;\n  display: flex; align-items: center; justify-content: center;\n  position: relative; overflow: hidden;\n  transition: all .2s ease;\n  box-shadow: inset 0 1px 2px rgba(255,255,255,.55), inset 0 -3px 6px rgba(0,0,0,.18), 0 2px 6px rgba(0,0,0,.15);\n}\n.dock-icon::before {\n  content: ''; position: absolute; top: 0; left: 0; right: 0; height: 55%;\n  background: linear-gradient(180deg, rgba(255,255,255,.55), rgba(255,255,255,0));\n  pointer-events: none;\n}\n.dock-icon > * { position: relative; z-index: 1; }\n\n/* Badge d'ic\u00f4ne \"3D\" color\u00e9 (menu plein \u00e9cran, profil, etc.) */\n.icon-badge-3d {\n  position: relative; overflow: hidden;\n  display: flex; align-items: center; justify-content: center;\n  box-shadow: inset 0 2px 3px rgba(255,255,255,.65), inset 0 -4px 8px rgba(0,0,0,.25), 0 4px 12px rgba(0,0,0,.22);\n}\n.icon-badge-3d::before {\n  content: ''; position: absolute; top: 0; left: 0; right: 0; height: 55%;\n  background: linear-gradient(180deg, rgba(255,255,255,.55), rgba(255,255,255,0));\n  pointer-events: none;\n}\n.icon-badge-3d > * { position: relative; z-index: 1; }\n\n/* Balayage lumineux p\u00e9riodique \u2014 .icon-sweep ihany (sidebar/menu), tsy amin'ny navbar/dock */\n.icon-sweep { position: relative; overflow: hidden; }\n.icon-sweep::after {\n  content: '';\n  position: absolute; top: 0; left: -60%; width: 40%; height: 100%;\n  background: linear-gradient(105deg, transparent, rgba(255,255,255,.8), transparent);\n  transform: skewX(-18deg);\n  animation: iconSweep 3.4s ease-in-out infinite;\n  animation-delay: calc(var(--sweep-delay, 0) * 1s);\n  pointer-events: none; z-index: 2;\n}\n@keyframes iconSweep {\n  0%   { left: -60%; }\n  35%  { left: 130%; }\n  100% { left: 130%; }\n}\n@media (prefers-reduced-motion: reduce) {\n  .icon-sweep::after { animation: none !important; }\n}\n/* Navbar : hauteur mitovy foana, tsy misy mihetsika/mamirapiratra */\n.dock-item.active .dock-icon {\n  box-shadow: 0 3px 10px var(--dock-glow, rgba(24,119,242,.45)), inset 0 1px 2px rgba(255,255,255,.6), inset 0 -3px 6px rgba(0,0,0,.22);\n}\n.dock-item.active { font-weight: 700; }\n\n/* Labelle navbar \u2014 soratra noire foana (tsy miloko araka ny ic\u00f4ne) */\n.dock-label {\n  font-size: 10px; font-weight: 600; margin-top: 3px;\n  color: #1C1E21; opacity: .68;\n  font-family: 'Poppins', sans-serif; letter-spacing: .1px;\n  transition: opacity .18s ease, font-weight .18s ease;\n}\n.dock-item.active .dock-label {\n  opacity: 1; font-weight: 700; color: #050505;\n}\n.dark .dock-label { color: #E4E6EB; opacity: .68; }\n.dark .dock-item.active .dock-label { color: #FFFFFF; opacity: 1; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 NAVIGATION RAPIDE (sidebar, horizontale premium) \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.quicknav-row {\n  display: flex; gap: 6px; padding: 6px 14px 14px;\n  overflow-x: auto; -webkit-overflow-scrolling: touch;\n  scrollbar-width: none; flex-shrink: 0; min-height: 92px;\n}\n.quicknav-row::-webkit-scrollbar { display: none; }\n.quicknav-item {\n  flex: 1 0 auto; min-width: 62px;\n  display: flex; flex-direction: column; align-items: center; gap: 6px;\n  padding: 12px 6px 10px;\n  background: linear-gradient(160deg, rgba(255,255,255,.9), rgba(247,248,250,.7));\n  border: 1px solid rgba(228,230,235,.9); border-radius: 18px;\n  cursor: pointer; position: relative;\n  transition: transform .16s ease, box-shadow .2s ease, border-color .2s ease;\n  box-shadow: 0 2px 8px rgba(5,5,5,.05), inset 0 1px 0 rgba(255,255,255,.8);\n}\n.dark .quicknav-item {\n  background: linear-gradient(160deg, rgba(30,34,44,.95), rgba(21,24,31,.85));\n  border-color: #232733;\n  box-shadow: 0 2px 8px rgba(0,0,0,.3), inset 0 1px 0 rgba(255,255,255,.05);\n}\n.quicknav-item:active { transform: scale(.94); }\n.quicknav-item.active {\n  border-color: #1877F2;\n  box-shadow: 0 4px 16px rgba(24,119,242,.22), inset 0 1px 0 rgba(255,255,255,.8);\n}\n.quicknav-icon {\n  width: 40px; height: 40px; border-radius: 13px;\n  display: flex; align-items: center; justify-content: center; position: relative;\n  box-shadow: inset 0 2px 3px rgba(255,255,255,.55), inset 0 -3px 6px rgba(0,0,0,.2), 0 3px 8px var(--glow, rgba(0,0,0,.15));\n}\n.quicknav-label {\n  font-size: 10.5px; font-weight: 600; font-family: 'Poppins', sans-serif;\n  white-space: nowrap; letter-spacing: .1px;\n}\n.quicknav-item.active .quicknav-label { font-weight: 800; }\n\n/* Spinner buffering (Reels) \u2014 miseho rehefa tena mbuffer ny video */\n.reel-spinner {\n  width: 46px; height: 46px; border-radius: 50%;\n  border: 3px solid rgba(255,255,255,.25);\n  border-top-color: #fff;\n  animation: reelSpin .8s linear infinite;\n}\n@keyframes reelSpin { to { transform: rotate(360deg); } }\n.nav-item {\n  display: flex; flex-direction: column; align-items: center;\n  padding: 6px 4px; cursor: pointer; border-radius: 12px;\n  transition: all .2s; color: var(--gray-txt); font-size: 11px; gap: 3px;\n  flex: 1; position: relative; font-family: 'Poppins', sans-serif;\n}\n.nav-item:hover { color: var(--blue); background: var(--blue-pale); }\n.nav-item.active { color: var(--blue); }\n.nav-item.active svg { color: var(--blue); }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 STORIES (format Facebook) \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.stories-strip {\n  display: flex; gap: 8px; overflow-x: auto;\n  padding: 10px 12px; scrollbar-width: none;\n  background: white; border-bottom: 1px solid var(--line);\n}\n.stories-strip::-webkit-scrollbar { display: none; }\n.story-card {\n  flex-shrink: 0; width: 104px; height: 170px;\n  border-radius: 14px; overflow: hidden; position: relative;\n  cursor: pointer; background: #000;\n  box-shadow: 0 2px 10px rgba(0,0,0,.18);\n  transition: transform .18s ease;\n}\n.story-card:active { transform: scale(.96); }\n.story-card video, .story-card img { width: 100%; height: 100%; object-fit: cover; }\n/* L'avatar garde sa petite taille (prioritaire sur .story-card img) */\n.story-card img.story-avatar, .story-avatar {\n  position: absolute; top: 8px; left: 8px;\n  width: 34px !important; height: 34px !important;\n  border-radius: 50%; object-fit: cover;\n  border: 3px solid var(--blue);\n  box-shadow: 0 0 0 2px white;\n  z-index: 2;\n}\n.story-name {\n  position: absolute; bottom: 6px; left: 8px; right: 8px;\n  color: white; font-size: 11px; font-weight: 600;\n  text-shadow: 0 1px 4px rgba(0,0,0,.8);\n  overflow: hidden; text-overflow: ellipsis; white-space: nowrap;\n}\n.story-gradient {\n  position: absolute; inset: 0;\n  background: linear-gradient(transparent 55%, rgba(0,0,0,.65));\n  pointer-events: none;\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 ACTIONS FACEBOOK \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.post-actions-row { display: flex; border-top: 1px solid var(--line); }\n.post-action-btn {\n  flex: 1; display: flex; align-items: center; justify-content: center;\n  gap: 5px; padding: 9px 0;\n  background: none; border: none; cursor: pointer;\n  color: var(--gray-txt); font-size: 13px; font-weight: 600;\n  font-family: 'Poppins', sans-serif; transition: background .15s;\n}\n.post-action-btn:hover { background: var(--canvas); color: var(--blue); }\n.post-action-btn.active { color: #FF2D8D; }\n\n.reactions-bar {\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 8px 16px; border-bottom: 1px solid var(--line);\n}\n.reactions-bar-left  { display: flex; align-items: center; gap: 4px; color: var(--gray-txt); font-size: 13px; }\n.reactions-bar-right { color: var(--gray-txt); font-size: 13px; cursor: pointer; }\n.reactions-bar-right:hover { text-decoration: underline; }\n\n.text-muted { color: var(--gray-txt) !important; }\n.text-dark  { color: var(--black) !important; }\n\n/* Toast */\n.toast {\n  position: fixed; bottom: 90px; left: 50%; transform: translateX(-50%);\n  background: var(--black); color: white;\n  padding: 12px 24px; border-radius: 25px;\n  font-size: 14px; z-index: 9999;\n  animation: fadeIn .3s ease;\n  box-shadow: 0 4px 20px rgba(0,0,0,.25);\n}\n\n.no-scrollbar::-webkit-scrollbar { display: none; }\n.no-scrollbar { scrollbar-width: none; }\n\n.search-input {\n  background: var(--canvas); border: 1.5px solid var(--line);\n  border-radius: 30px; padding: 10px 16px;\n  font-family: 'Poppins', sans-serif; font-size: 14px;\n  color: var(--black); width: 100%;\n}\n.search-input::placeholder { color: #8A8D91; }\n.search-input:focus { outline: none; border-color: var(--blue); }\n\n@media (prefers-reduced-motion: reduce) {\n  .btn-primary::after, .btn-secondary, .btn-gold, .logo-shimmer, .text-gold-shine { animation: none !important; }\n}\n";
const SETTINGS_SRC="// src/pages/Settings.jsx\nimport { useNavigate } from 'react-router-dom';\nimport { useAuth } from '../context/AuthContext';\nimport { useLang } from '../context/LanguageContext';\nimport { useTheme } from '../context/ThemeContext';\nimport { useState, useEffect } from 'react';\nimport { isDataSaverOn, setDataSaver } from '../utils/dataSaver';\nimport BoostOrderModal from '../components/BoostOrderModal';\nimport {\n  HiLogout, HiGlobe, HiColorSwatch, HiUser, HiShieldCheck,\n  HiChevronRight, HiStar, HiSpeakerphone, HiInformationCircle\n} from 'react-icons/hi';\n\nexport default function Settings() {\n  const { logout, currentUser, userProfile } = useAuth();\n  const { t } = useLang();\n  const { theme } = useTheme();\n  const navigate = useNavigate();\n  const [dataSaver, setDataSaverState] = useState(false);\n  const [boostOpen, setBoostOpen] = useState(false);\n  useEffect(() => { setDataSaverState(isDataSaverOn()); }, []);\n  function toggleDataSaver() {\n    const next = !dataSaver;\n    setDataSaverState(next);\n    setDataSaver(next);\n  }\n\n  async function handleLogout() {\n    if (!window.confirm('Hivoaka ve ianao?')) return;\n    await logout();\n    navigate('/login');\n  }\n\n  const menuItems = [\n    {\n      icon: HiGlobe, label: t('language'),\n      sublabel: 'Malagasy / Fran\u00e7ais / English',\n      path: '/settings/language', color: '#3b82f6'\n    },\n    {\n      icon: HiColorSwatch, label: t('appearance'),\n      sublabel: theme === 'dark' ? 'Mode nuit' : 'Mode clair',\n      path: '/settings/appearance', color: '#8b5cf6'\n    },\n    {\n      icon: HiShieldCheck, label: 'S\u00e9curit\u00e9',\n      sublabel: 'Email, mot de passe, aide',\n      path: '/settings/security', color: '#10b981'\n    },\n    {\n      icon: HiStar, label: 'Compte VIP',\n      sublabel: 'Badge rose + avantages exclusifs',\n      path: '/vip', color: '#f59e0b'\n    },\n    {\n      icon: HiSpeakerphone, label: 'Booster mon profil',\n      sublabel: 'Augmenter la visibilit\u00e9',\n      path: '#boost', color: '#1877F2'\n    },\n  ];\n\n  return (\n    <div style={{ padding: '16px 12px' }}>\n      <h2 style={{ fontWeight: 700, fontSize: 20, color: '#1877F2', marginBottom: 20 }}>{t('settings')}</h2>\n\n      {/* Profile summary */}\n      <div className=\"card\" style={{ padding: 16, marginBottom: 16, display: 'flex', alignItems: 'center', gap: 12 }}>\n        <div style={{ position: 'relative' }}>\n          <img\n            src={userProfile?.photoURL || `https://ui-avatars.com/api/?name=${encodeURIComponent(userProfile?.fullName||'U')}&background=1877F2&color=fff`}\n            alt=\"\" className=\"avatar\" style={{ width: 54, height: 54 }}\n          />\n          {userProfile?.isVip && (\n            <img src='/vip-badge.png' style={{ width:32, height:32, marginLeft:5, verticalAlign:'middle', display:'inline-block', flexShrink:0, objectFit:'contain' }} alt='VIP'/>\n          )}\n        </div>\n        <div style={{ flex: 1 }}>\n          <p style={{ fontWeight: 700, fontSize: 16 }}>{userProfile?.fullName}</p>\n          <p style={{ fontSize: 13, color: '#65676B' }}>@{userProfile?.username}</p>\n          <p style={{ fontSize: 12, color: '#65676B' }}>{currentUser?.email}</p>\n        </div>\n        <button\n          onClick={() => navigate(`/profile/${currentUser?.uid}`)}\n          style={{ background: '#E4E6EB', border: 'none', borderRadius: 20, padding: '6px 14px', color: '#1877F2', fontWeight: 600, cursor: 'pointer', fontSize: 13 }}\n        >\n          <HiUser size={14} style={{ display: 'inline', marginRight: 4 }} />\n          {t('editProfile')}\n        </button>\n      </div>\n\n      {/* \u00c9conomiser des donn\u00e9es */}\n      <div className=\"card\" style={{ padding: 16, marginBottom: 16, display: 'flex', alignItems: 'center', gap: 14 }}>\n        <div style={{ width: 38, height: 38, borderRadius: 12, background: '#1877F215', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, fontSize: 18 }}>\ud83d\udcf6</div>\n        <div style={{ flex: 1 }}>\n          <p style={{ fontWeight: 600, fontSize: 14 }}>\u00c9conomiser des donn\u00e9es</p>\n          <p style={{ fontSize: 12, color: '#65676B' }}>\n            {dataSaver ? \"Les vid\u00e9os ne se lancent plus automatiquement\" : \"Les vid\u00e9os peuvent se lancer automatiquement\"}\n          </p>\n        </div>\n        <button onClick={toggleDataSaver} role=\"switch\" aria-checked={dataSaver}\n          style={{ width: 46, height: 26, borderRadius: 20, border: 'none', cursor: 'pointer', flexShrink: 0,\n            background: dataSaver ? '#1877F2' : '#E4E6EB', position: 'relative', transition: 'background .2s' }}>\n          <span style={{ position: 'absolute', top: 3, left: dataSaver ? 23 : 3, width: 20, height: 20, borderRadius: '50%', background: 'white', boxShadow: '0 1px 3px rgba(0,0,0,.3)', transition: 'left .2s' }} />\n        </button>\n      </div>\n\n      {/* Menu items */}\n      <div className=\"card\" style={{ overflow: 'hidden', marginBottom: 16 }}>\n        {menuItems.map((item, i) => {\n          const Icon = item.icon;\n          return (\n            <div\n              key={item.path}\n              onClick={() => item.path === '#boost' ? setBoostOpen(true) : navigate(item.path)}\n              style={{\n                display: 'flex', alignItems: 'center', gap: 14,\n                padding: '14px 16px', cursor: 'pointer',\n                borderBottom: i < menuItems.length - 1 ? '1px solid #F0F2F5' : 'none',\n                transition: 'background 0.15s'\n              }}\n              onMouseEnter={e => e.currentTarget.style.background = '#F0F2F5'}\n              onMouseLeave={e => e.currentTarget.style.background = 'transparent'}\n            >\n              <div style={{ width: 38, height: 38, borderRadius: 12, background: item.color + '15', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>\n                <Icon size={20} color={item.color} />\n              </div>\n              <div style={{ flex: 1 }}>\n                <p style={{ fontWeight: 600, fontSize: 14 }}>{item.label}</p>\n                <p style={{ fontSize: 12, color: '#65676B' }}>{item.sublabel}</p>\n              </div>\n              <HiChevronRight size={18} color=\"#65676B\" />\n            </div>\n          );\n        })}\n      </div>\n\n      {/* About */}\n      <div className=\"card\" style={{ padding: 16, marginBottom: 16 }}>\n        <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 10 }}>\n          <HiInformationCircle color=\"#1877F2\" size={20} />\n          <h3 style={{ fontWeight: 700, fontSize: 15 }}>Momba Trengo</h3>\n        </div>\n        <p style={{ fontSize: 13, color: '#65676B', lineHeight: 1.6 }}>\n          Trengo dia tambajotra sosialy malagasy \u2014 ahazoanao mizara, mivarotra ary miresaka amin'ny namanao.\n        </p>\n        <p style={{ fontSize: 12, color: '#65676B', marginTop: 8 }}>Version 2.0.0</p>\n      </div>\n\n      {/* Logout */}\n      <button\n        onClick={handleLogout}\n        style={{\n          width: '100%', padding: 14, borderRadius: 16, border: '2px solid #1877F2',\n          background: 'white', cursor: 'pointer', color: '#1877F2',\n          fontFamily: 'Poppins', fontWeight: 700, fontSize: 15,\n          display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 8,\n          transition: 'all 0.2s',\n        }}\n        onMouseEnter={e => { e.currentTarget.style.background = '#1877F2'; e.currentTarget.style.color = 'white'; }}\n        onMouseLeave={e => { e.currentTarget.style.background = 'white'; e.currentTarget.style.color = '#1877F2'; }}\n      >\n        <HiLogout size={20} /> {t('logout')}\n      </button>\n\n      {boostOpen && currentUser && (\n        <BoostOrderModal\n          target={{ type: 'profile', id: currentUser.uid, ownerUid: currentUser.uid, title: userProfile?.fullName || 'Mon profil', thumbnailURL: userProfile?.photoURL || '' }}\n          onClose={() => setBoostOpen(false)}\n        />\n      )}\n    </div>\n  );\n}\n";
const REELS_SRC="// src/pages/Reels.jsx \u2014 TikTok style vertical scroll\nimport { useState, useEffect, useRef, useCallback } from 'react';\nimport { useLocation, useNavigate } from 'react-router-dom';\nimport {\n  collection, query, orderBy, onSnapshot, doc, updateDoc,\n  addDoc, serverTimestamp, arrayUnion, arrayRemove, deleteDoc, getDoc\n} from 'firebase/firestore';\nimport { db } from '../firebase';\nimport { useAuth } from '../context/AuthContext';\nimport { useLang } from '../context/LanguageContext';\nimport { uploadToTelegram } from '../utils/telegram';\nimport { sendPushNotification } from '../utils/onesignal';\nimport { isDataSaverOn, subscribeDataSaver } from '../utils/dataSaver';\nimport { downloadMedia } from '../utils/download';\nimport BoostOrderModal from '../components/BoostOrderModal';\nimport ShareModal from '../components/ShareModal';\nimport JejoStudio from '../components/JejoStudio';\nimport { StoryMusicPlayer } from '../components/StoryStudio';\nimport { v4 as uuidv4 } from 'uuid';\nimport {\n  HiHeart, HiOutlineHeart, HiChat, HiShare, HiArrowLeft, HiBookmark,\n  HiDownload, HiSpeakerphone, HiDotsVertical, HiTrash,\n  HiPencil, HiReply, HiPhotograph, HiVideoCamera, HiX\n} from 'react-icons/hi';\n\nconst REACTIONS = ['\u2764\ufe0f','\ud83d\ude02','\ud83d\ude2e','\ud83d\ude22','\ud83d\ude21','\ud83d\udc4d'];\n\nfunction VIPBadge() {\n  return <img src='/vip-badge.png' style={{ width:24, height:24, marginLeft:5, verticalAlign:'middle', display:'inline-block', flexShrink:0, objectFit:'contain' }} alt='VIP'/>;\n}\n\nexport default function Reels() {\n  const { currentUser, userProfile, setUserProfile } = useAuth();\n  const { t } = useLang();\n  const navigate = useNavigate();\n  const location = useLocation();\n\n  const [posts,             setPosts]           = useState([]);\n  const [boostTarget,       setBoostTarget]     = useState(null);\n  const [activeIndex,       setActiveIndex]     = useState(0);\n  const [showReactions,     setShowReactions]   = useState({});\n  const [openComments,      setOpenComments]    = useState(false);\n  const [commentText,       setCommentText]     = useState('');\n  const [commentMedia,      setCommentMedia]    = useState(null);\n  const [replyTo,           setReplyTo]         = useState(null);\n  const [editCmt,           setEditCmt]         = useState(null);\n  const [cmtReactPicker,    setCmtReactPicker]  = useState(null);\n  const [postMenu,          setPostMenu]        = useState(false);\n  const [reactionModal,     setRM]              = useState(null);\n  const [videoFit,          setVideoFit]        = useState({});   // idx -> 'cover' | 'contain'\n  const [pausedIdx,         setPausedIdx]        = useState(null);\n  const [bufferingIdx,      setBufferingIdx]     = useState(null);\n  const [dataSaver,         setDataSaverState]   = useState(isDataSaverOn());\n  useEffect(() => subscribeDataSaver(setDataSaverState), []);\n  const [shareModal,        setShareModal]       = useState(null);\n  const [jejoStudio,        setJejoStudio]       = useState(false);\n\n  const videoRefs  = useRef({});\n  const containerRef = useRef();\n  const cPhotoRef  = useRef();\n  const cVideoRef  = useRef();\n\n  useEffect(() => {\n    const q = query(collection(db,'posts'), orderBy('createdAt','desc'));\n    const unsub = onSnapshot(q, snap => {\n      const all = snap.docs.map(d=>({id:d.id,...d.data()})).filter(p=>p.mediaType==='video'&&p.mediaURL);\n      setPosts(all);\n      if (location.state?.startId) {\n        const idx = all.findIndex(p=>p.id===location.state.startId);\n        if (idx>=0) {\n          setActiveIndex(idx);\n          setTimeout(()=>{\n            if(containerRef.current){\n              containerRef.current.scrollTop = idx * containerRef.current.clientHeight;\n            }\n          }, 100);\n        }\n      }\n    });\n    return unsub;\n  }, []);\n\n  useEffect(() => {\n    Object.entries(videoRefs.current).forEach(([idx,video]) => {\n      if (!video) return;\n      if (parseInt(idx)===activeIndex) {\n        if (dataSaver) {\n          // \u00c9conomiser des donn\u00e9es : pas de lecture automatique \u2014 le mpampiasa doit tap\n          video.pause();\n          setPausedIdx(activeIndex);\n        } else {\n          video.play().then(() => setPausedIdx(p => p===activeIndex?null:p)).catch(()=>{});\n        }\n      }\n      else { video.pause(); video.currentTime=0; }\n    });\n  }, [activeIndex, posts.length, dataSaver]);\n\n  useEffect(() => {\n    const fn = () => setPostMenu(false);\n    document.addEventListener('click', fn);\n    return () => document.removeEventListener('click', fn);\n  }, []);\n\n  const handleScroll = useCallback(() => {\n    if (!containerRef.current) return;\n    const { scrollTop, clientHeight } = containerRef.current;\n    const newIndex = Math.round(scrollTop / clientHeight);\n    if (newIndex !== activeIndex) {\n      setActiveIndex(newIndex);\n      setOpenComments(false);\n      setShowReactions({});\n      setPostMenu(false);\n    }\n  }, [activeIndex]);\n\n  async function toggleSave(postId) {\n    const saved = userProfile?.saved || [];\n    const isSaved = saved.includes(postId);\n    try {\n      const { arrayUnion, arrayRemove } = await import('firebase/firestore');\n      await updateDoc(doc(db, 'users', currentUser.uid), { saved: isSaved ? arrayRemove(postId) : arrayUnion(postId) });\n      setUserProfile(p => ({ ...p, saved: isSaved ? (p.saved||[]).filter(id => id !== postId) : [...(p.saved||[]), postId] }));\n    } catch (err) { console.error(err); }\n  }\n\n  async function reactToPost(postId, emoji) {\n    const post = posts.find(p=>p.id===postId); if (!post) return;\n    const reactions = post.reactions||{}, my = reactions[currentUser.uid];\n    if (my===emoji) {\n      const u={...reactions}; delete u[currentUser.uid];\n      await updateDoc(doc(db,'posts',postId),{reactions:u});\n    } else {\n      await updateDoc(doc(db,'posts',postId),{[`reactions.${currentUser.uid}`]:emoji});\n      if (post.uid!==currentUser.uid) {\n        await addDoc(collection(db,'notifications'),{\n          toUid:post.uid, fromUid:currentUser.uid,\n          fromName:userProfile.fullName, fromPhoto:userProfile.photoURL||'',\n          type:'reaction', postId, emoji,\n          message:`${userProfile.fullName} a r\u00e9agi ${emoji} \u00e0 votre reel`,\n          read:false, createdAt:serverTimestamp(),\n        });\n        sendPushNotification({toExternalId:post.uid, title:userProfile.fullName, message:`a r\u00e9agi ${emoji}`, data:{type:'reaction',postId}});\n      }\n    }\n    setShowReactions({});\n  }\n\n  async function openReactionModal(post) {\n    const reactions = post.reactions||{};\n    if (!Object.keys(reactions).length) return;\n    const userData = {};\n    await Promise.all(Object.keys(reactions).map(async uid => {\n      try {\n        const s = await getDoc(doc(db,'users',uid));\n        userData[uid] = s.exists()?{name:s.data().fullName,photo:s.data().photoURL}:{name:uid,photo:''};\n      } catch { userData[uid]={name:uid,photo:''}; }\n    }));\n    setRM({reactions,userData});\n  }\n\n  async function reactToCmt(postId, cmtId, emoji) {\n    const post = posts.find(p=>p.id===postId); if (!post) return;\n    const updated = post.comments.map(c => {\n      if (c.id!==cmtId) return c;\n      const reactions = c.reactions||{}, my = reactions[currentUser.uid];\n      if (my===emoji) { const u={...reactions}; delete u[currentUser.uid]; return {...c,reactions:u}; }\n      return {...c,reactions:{...reactions,[currentUser.uid]:emoji}};\n    });\n    await updateDoc(doc(db,'posts',postId),{comments:updated});\n    setCmtReactPicker(null);\n  }\n\n  async function addComment(postId) {\n    const post = posts.find(p=>p.id===postId); if (!post) return;\n    const rt = replyTo;\n    const raw = rt?`@${rt} ${commentText}`:commentText;\n    const text = raw.trim(); const media = commentMedia;\n    if (!text&&!media) return;\n    let mediaURL='', cMT='';\n    if (media) { try { const r=await uploadToTelegram(media.file); mediaURL=r.url; cMT=r.type; } catch {} }\n    const cmt = {\n      id:uuidv4(), uid:currentUser.uid,\n      authorName:userProfile.fullName, authorPhoto:userProfile.photoURL||'',\n      authorIsVip:userProfile.isVip||false,\n      text:text.slice(0,500), mediaURL, mediaType:cMT,\n      createdAt:new Date().toISOString(),\n    };\n    await updateDoc(doc(db,'posts',postId),{comments:arrayUnion(cmt)});\n    setCommentText(''); setCommentMedia(null); setReplyTo(null);\n    if (post.uid!==currentUser.uid) {\n      await addDoc(collection(db,'notifications'),{\n        toUid:post.uid, fromUid:currentUser.uid,\n        fromName:userProfile.fullName, fromPhoto:userProfile.photoURL||'',\n        type:'comment', postId,\n        message:`${userProfile.fullName} a comment\u00e9 votre reel`,\n        read:false, createdAt:serverTimestamp(),\n      });\n      sendPushNotification({toExternalId:post.uid, title:userProfile.fullName, message:text?`a comment\u00e9 : \"${text.slice(0,50)}\"`:' a comment\u00e9', data:{type:'comment',postId}});\n    }\n  }\n\n  async function deleteCmt(postId, cmt) {\n    if (cmt.uid!==currentUser.uid && post.uid!==currentUser.uid) return;\n    if (!window.confirm('Supprimer ce commentaire ?')) return;\n    await updateDoc(doc(db,'posts',postId),{comments:arrayRemove(cmt)});\n  }\n\n  async function saveEditCmt(postId, oldCmt, newText) {\n    if (!newText.trim()) return;\n    const post = posts.find(p=>p.id===postId); if (!post) return;\n    const updated = post.comments.map(c=>c.id===oldCmt.id?{...c,text:newText.trim()}:c);\n    await updateDoc(doc(db,'posts',postId),{comments:updated});\n    setEditCmt(null);\n  }\n\n  async function deletePost(postId) {\n    const post = posts.find(p=>p.id===postId);\n    if (!post||post.uid!==currentUser.uid) return;\n    if (!window.confirm('Supprimer ce reel ?')) return;\n    await deleteDoc(doc(db,'posts',postId));\n  }\n\n  function sharePost(post) {\n    setShareModal(post);\n  }\n\n  function countReactions(r={}) {\n    const c={}; Object.values(r).forEach(e=>{c[e]=(c[e]||0)+1;}); return c;\n  }\n\n  if (posts.length===0) { return ( <div style={{ display:\"flex\", flexDirection:\"column\", alignItems:\"center\", justifyContent:\"center\", height:\"100dvh\", color:\"#65676B\", gap:8 }}> <style>{`@keyframes dot { 0%,80%,100%{opacity:0} 40%{opacity:1} } .d1{animation:dot 1.4s infinite .0s} .d2{animation:dot 1.4s infinite .2s} .d3{animation:dot 1.4s infinite .4s}`}</style> <p style={{ fontSize:18, fontWeight:600 }}>Chargement<span className=\"d1\">.</span><span className=\"d2\">.</span><span className=\"d3\">.</span></p> <button onClick={() => setJejoStudio(true)} aria-label=\"Cr\u00e9er un Jejo\" style={{ marginTop:12, width:64, height:64, borderRadius:'50%', background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'none', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', color:'#fff', boxShadow:'0 6px 20px rgba(255,45,141,.5)' }}><svg width=\"32\" height=\"32\" viewBox=\"0 0 24 24\" fill=\"none\"><path d=\"M12 5v14M5 12h14\" stroke=\"currentColor\" strokeWidth=\"2.6\" strokeLinecap=\"round\"/></svg></button> {jejoStudio && <JejoStudio currentUser={currentUser} userProfile={userProfile} onClose={() => setJejoStudio(false)} onPublished={() => setJejoStudio(false)} />} </div> ); } if (posts.length===-999) {\n    return (\n      <div style={{ display:'flex', flexDirection:'column', alignItems:'center', justifyContent:'center', height:'100dvh', color:'#65676B', gap:16 }}>\n        <span style={{ fontSize:48 }}>\ud83c\udfac</span>\n        <p style={{ fontSize:15 }}>Tsy misy reels mbola</p>\n        <button onClick={() => navigate('/')} className=\"btn-primary\" style={{ fontSize:13 }}>Miverina</button>\n      </div>\n    );\n  }\n\n  const activePost = posts[activeIndex];\n\n  return (\n    <div style={{ position:'relative', height:'100dvh', overflow:'hidden', background:'#000' }}>\n      {/* Back button */}\n      <button onClick={() => navigate(-1)} style={{ position:'absolute', top:14, left:14, zIndex:50, background:'rgba(0,0,0,0.4)', border:'none', borderRadius:'50%', width:38, height:38, display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', color:'white' }}>\n        <HiArrowLeft size={20}/>\n      </button>\n      <button onClick={() => setJejoStudio(true)} aria-label=\"Cr\u00e9er un Jejo\" style={{ position:'absolute', bottom:'calc(24px + env(safe-area-inset-bottom))', left:'50%', transform:'translateX(-50%)', zIndex:60, width:60, height:60, borderRadius:'50%', background:'linear-gradient(135deg,#FF2D8D,#FF7AB8)', border:'3px solid rgba(255,255,255,.9)', display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', color:'#fff', boxShadow:'0 6px 20px rgba(255,45,141,.6)' }}>\n        <svg width=\"30\" height=\"30\" viewBox=\"0 0 24 24\" fill=\"none\"><path d=\"M12 5v14M5 12h14\" stroke=\"currentColor\" strokeWidth=\"2.6\" strokeLinecap=\"round\"/></svg>\n      </button>\n      {jejoStudio && <JejoStudio currentUser={currentUser} userProfile={userProfile} onClose={() => setJejoStudio(false)} onPublished={() => setJejoStudio(false)} />}\n\n      {/* Video feed */}\n      <div ref={containerRef} onScroll={handleScroll} style={{ height:'100%', overflowY:'scroll', scrollSnapType:'y mandatory', scrollbarWidth:'none' }}>\n        {posts.map((post, idx) => {\n          const myR = post.reactions?.[currentUser.uid];\n          const total = Object.keys(post.reactions||{}).length;\n          const isOwn = post.uid===currentUser.uid;\n          return (\n            <div key={post.id} style={{ height:'100%', scrollSnapAlign:'start', position:'relative', flexShrink:0 }}>\n              <video\n                ref={el=>videoRefs.current[idx]=el}\n                src={post.mediaURL} loop playsInline muted={!!post.music?.url}\n                poster={post.thumbURL || undefined}\n                preload={dataSaver ? 'none' : (Math.abs(idx - activeIndex) <= 1 ? 'auto' : 'metadata')}\n                style={{ width:'100%', height:'100%', objectFit: videoFit[idx] || 'cover', background:'#000', filter: post.filter || 'none' }}\n                onLoadedMetadata={e => {\n                  const v = e.target;\n                  try { v.playbackRate = post.speed || 1; } catch {}\n                  // Portrait/carr\u00e9 = cover (mameno \u00e9cran) ; paysage tena marina = contain (letterbox, tsy tapaka)\n                  const fit = (v.videoHeight >= v.videoWidth * 0.95) ? 'cover' : 'contain';\n                  setVideoFit(p => p[idx] === fit ? p : { ...p, [idx]: fit });\n                }}\n                onWaiting={() => idx===activeIndex && setBufferingIdx(idx)}\n                onPlaying={() => setBufferingIdx(p => p===idx ? null : p)}\n                onCanPlay={() => setBufferingIdx(p => p===idx ? null : p)}\n                onPlay={() => setPausedIdx(p => p===idx?null:p)}\n                onPause={() => idx===activeIndex && setPausedIdx(idx)}\n                onClick={() => { const v=videoRefs.current[idx]; if(v) v.paused?v.play().catch(()=>{}):v.pause(); }}\n              />\n              {post.music?.url && idx===activeIndex && <StoryMusicPlayer url={post.music.url} start={post.music.start} paused={pausedIdx===idx} />}\n              <div style={{ position:'absolute', inset:0, background:'linear-gradient(to top, rgba(0,0,0,0.7) 0%, transparent 50%)', pointerEvents:'none' }}/>\n\n              {/* Spinner buffering \u2014 miseho rehefa tena mbuffer ihany (tsy paused manuel) */}\n              {idx===activeIndex && bufferingIdx===idx && pausedIdx!==idx && (\n                <div style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center', pointerEvents:'none' }}>\n                  <div className=\"reel-spinner\" />\n                </div>\n              )}\n\n              {/* Ic\u00f4ne \"tap pour lire\" \u2014 rehefa paused (data saver na tap manuel) */}\n              {idx===activeIndex && pausedIdx===idx && (\n                <div onClick={() => { const v=videoRefs.current[idx]; if(v) v.play().catch(()=>{}); }}\n                  style={{ position:'absolute', inset:0, display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer' }}>\n                  <div style={{ width:70, height:70, background:'rgba(0,0,0,0.45)', border:'2px solid rgba(255,255,255,.7)', borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center' }}>\n                    <span style={{ color:'white', fontSize:28, marginLeft:4 }}>\u25b6</span>\n                  </div>\n                </div>\n              )}\n\n              {/* Author info */}\n              <div style={{ position:'absolute', bottom:80, left:14, right:80 }}>\n                <div onClick={() => navigate(`/profile/${post.uid}`)} style={{ display:'flex', alignItems:'center', gap:8, cursor:'pointer', marginBottom:8 }}>\n                  <img src={post.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(post.authorName||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:36, height:36, borderRadius:'50%', border:'2px solid white', flexShrink:0 }}/>\n                  <p style={{ color:'white', fontWeight:700, fontSize:14 }}>{post.authorName}{post.authorIsVip&&<VIPBadge/>}</p>\n                </div>\n                {post.content&&<p style={{ color:'rgba(255,255,255,0.9)', fontSize:13, lineHeight:1.5, display:'-webkit-box', WebkitLineClamp:2, WebkitBoxOrient:'vertical', overflow:'hidden' }}>{post.content}</p>}\n              </div>\n\n              {/* Right actions */}\n              <div style={{ position:'absolute', right:14, bottom:80, display:'flex', flexDirection:'column', alignItems:'center', gap:20 }}>\n                {/* Reactions */}\n                <div style={{ position:'relative' }}>\n                  {idx===activeIndex&&showReactions[idx]&&(\n                    <div style={{ position:'absolute', right:50, bottom:0, background:'rgba(0,0,0,0.7)', borderRadius:30, padding:'8px 10px', display:'flex', gap:8 }}>\n                      {REACTIONS.map(emoji=><button key={emoji} onClick={()=>reactToPost(post.id,emoji)} style={{ background:'none', border:'none', cursor:'pointer', fontSize:24 }}>{emoji}</button>)}\n                    </div>\n                  )}\n                  <div style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:3 }}>\n                    <button onClick={()=>idx===activeIndex&&setShowReactions(p=>({...p,[idx]:!p[idx]}))} style={{ background:'none', border:'none', cursor:'pointer', color:myR?'#63A9FF':'white' }}>\n                      {myR?<HiHeart size={28} color=\"#63A9FF\"/>:<HiOutlineHeart size={28}/>}\n                    </button>\n                    <span onClick={()=>idx===activeIndex&&openReactionModal(post)} style={{ color:'white', fontSize:12, cursor:'pointer' }}>{total}</span>\n                  </div>\n                </div>\n\n                {/* Comment */}\n                <div style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:3 }}>\n                  <button onClick={()=>idx===activeIndex&&setOpenComments(p=>!p)} style={{ background:'none', border:'none', cursor:'pointer', color:'white' }}>\n                    <HiChat size={28}/>\n                  </button>\n                  <span style={{ color:'white', fontSize:12 }}>{post.comments?.length||0}</span>\n                </div>\n\n                {/* Share */}\n                <button onClick={()=>sharePost(post)} style={{ background:'none', border:'none', cursor:'pointer', color:'white' }}>\n                  <HiShare size={26}/>\n                </button>\n\n                {/* Download */}\n                <button onClick={()=>downloadMedia(post.mediaURL, 'video')} style={{ background:'none', border:'none', cursor:'pointer', color:'white' }}>\n                  <HiDownload size={26}/>\n                </button>\n\n                {/* Enregistrer */}\n                <div style={{ display:'flex', flexDirection:'column', alignItems:'center', gap:3 }}>\n                  <button onClick={()=>toggleSave(post.id)} style={{ background:'none', border:'none', cursor:'pointer', color:(userProfile?.saved||[]).includes(post.id)?'#F2B300':'white' }}>\n                    <HiBookmark size={26}/>\n                  </button>\n                  <span style={{ color:'white', fontSize:11 }}>{(userProfile?.saved||[]).includes(post.id)?'Enregistr\u00e9':'Enregistrer'}</span>\n                </div>\n\n                {/* Boost */}\n                {isOwn && (\n                  <button onClick={()=>setBoostTarget({ type:'post', id:post.id, ownerUid:post.uid, title:(post.content||'').slice(0,60)||'Ma video', thumbnailURL:post.thumbURL||post.mediaURL||'' })} style={{ background:'none', border:'none', cursor:'pointer', color:'white' }}>\n                    <HiSpeakerphone size={24}/>\n                  </button>\n                )}\n\n                {/* Menu 3 points \u2014 anao ihany */}\n                {isOwn&&(\n                  <div style={{ position:'relative' }} onClick={e=>e.stopPropagation()}>\n                    <button onClick={()=>idx===activeIndex&&setPostMenu(p=>!p)} style={{ background:'none', border:'none', cursor:'pointer', color:'white' }}>\n                      <HiDotsVertical size={24}/>\n                    </button>\n                    {idx===activeIndex&&postMenu&&(\n                      <div style={{ position:'absolute', right:40, bottom:0, background:'rgba(0,0,0,0.85)', borderRadius:12, minWidth:150, overflow:'hidden', border:'1px solid #232733' }}>\n                        <button onClick={()=>{deletePost(post.id);setPostMenu(false);}} style={{ width:'100%', display:'flex', alignItems:'center', gap:10, padding:'11px 16px', background:'none', border:'none', cursor:'pointer', color:'#63A9FF', fontSize:14, fontFamily:'Poppins' }}>\n                          <HiTrash size={15}/> Supprimer\n                        </button>\n                      </div>\n                    )}\n                  </div>\n                )}\n              </div>\n            </div>\n          );\n        })}\n      </div>\n\n      {/* Comments panel */}\n      {openComments&&activePost&&(\n        <div style={{ position:'absolute', bottom:0, left:0, right:0, background:'rgba(0,0,0,0.92)', borderRadius:'20px 20px 0 0', padding:'16px 16px 20px', maxHeight:'65%', display:'flex', flexDirection:'column', zIndex:100 }}>\n          <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:12 }}>\n            <p style={{ color:'white', fontWeight:700 }}>Commentaires ({activePost.comments?.length||0})</p>\n            <button onClick={()=>setOpenComments(false)} style={{ background:'none', border:'none', color:'#65676B', cursor:'pointer' }}><HiX size={20}/></button>\n          </div>\n          <div style={{ flex:1, overflowY:'auto', marginBottom:10 }}>\n            {activePost.comments?.map(c=>(\n              <div key={c.id} style={{ display:'flex', gap:8, marginBottom:12 }}>\n                <img src={c.authorPhoto||`https://ui-avatars.com/api/?name=${encodeURIComponent(c.authorName||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:32, height:32, borderRadius:'50%', flexShrink:0, cursor:'pointer' }} onClick={()=>navigate(`/profile/${c.uid}`)}/>\n                <div style={{ flex:1 }}>\n                  <div style={{ background:'rgba(255,255,255,0.1)', borderRadius:12, padding:'8px 10px' }}>\n                    <span style={{ color:'#63A9FF', fontWeight:700, fontSize:13 }}>{c.authorName}{c.authorIsVip&&<VIPBadge/>}{' '}</span>\n                    {c.text&&<span style={{ color:'white', fontSize:13 }}>{c.text}</span>}\n                    {c.mediaURL&&<div style={{ marginTop:4 }}>{c.mediaType==='image'?<img src={c.mediaURL} alt=\"\" style={{ maxWidth:180, borderRadius:8 }}/>:<video src={c.mediaURL} controls style={{ maxWidth:180, borderRadius:8 }}/>}</div>}\n                  </div>\n                  <div style={{ display:'flex', gap:10, marginTop:4, flexWrap:'wrap' }}>\n                    <button onClick={()=>setReplyTo(c.authorName)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', fontSize:11, display:'flex', alignItems:'center', gap:3 }}><HiReply size={12}/> R\u00e9pondre</button>\n                    <button onClick={()=>setCmtReactPicker(p=>p===c.id?null:c.id)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', fontSize:11 }}>{c.reactions?.[currentUser.uid]||'\ud83d\ude0a'} {Object.keys(c.reactions||{}).length||''}</button>\n                    {cmtReactPicker===c.id&&<div style={{ display:'flex', gap:4, background:'rgba(0,0,0,0.8)', borderRadius:20, padding:'4px 8px' }}>{['\u2764\ufe0f','\ud83d\ude02','\ud83d\ude2e','\ud83d\ude22','\ud83d\udc4d','\ud83d\udd25'].map(em=><span key={em} onClick={()=>reactToCmt(activePost.id,c.id,em)} style={{ fontSize:18, cursor:'pointer' }}>{em}</span>)}</div>}\n                    {(c.uid===currentUser.uid||activePost.uid===currentUser.uid)&&<>\n                      <button onClick={()=>setEditCmt({cmt:c,text:c.text})} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B', fontSize:11, display:'flex', alignItems:'center', gap:3 }}><HiPencil size={12}/> Modifier</button>\n                      <button onClick={()=>deleteCmt(activePost.id,c)} style={{ background:'none', border:'none', cursor:'pointer', color:'#63A9FF', fontSize:11, display:'flex', alignItems:'center', gap:3 }}><HiTrash size={12}/> Supprimer</button>\n                    </>}\n                  </div>\n                </div>\n              </div>\n            ))}\n          </div>\n\n          {replyTo&&(\n            <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:8, background:'rgba(255,255,255,0.1)', padding:'6px 10px', borderRadius:10 }}>\n              <HiReply size={14} color=\"#63A9FF\"/>\n              <span style={{ fontSize:12, color:'#65676B' }}>R\u00e9pondre \u00e0 <strong style={{ color:'white' }}>{replyTo}</strong></span>\n              <button onClick={()=>setReplyTo(null)} style={{ marginLeft:'auto', background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={14}/></button>\n            </div>\n          )}\n\n          {commentMedia&&(\n            <div style={{ position:'relative', marginBottom:8, display:'inline-block' }}>\n              {commentMedia.type==='image'?<img src={commentMedia.preview} alt=\"\" style={{ maxWidth:120, borderRadius:8 }}/>:<video src={commentMedia.preview} style={{ maxWidth:120, borderRadius:8 }}/>}\n              <button onClick={()=>setCommentMedia(null)} style={{ position:'absolute', top:2, right:2, background:'rgba(0,0,0,0.6)', border:'none', borderRadius:'50%', width:20, height:20, cursor:'pointer', color:'white', fontSize:10 }}>\u2715</button>\n            </div>\n          )}\n\n          <input ref={cPhotoRef} type=\"file\" accept=\"image/*\" style={{ display:'none' }} onChange={e=>{const f=e.target.files[0];if(f)setCommentMedia({file:f,type:'image',preview:URL.createObjectURL(f)});}}/>\n          <input ref={cVideoRef} type=\"file\" accept=\"video/*\" style={{ display:'none' }} onChange={e=>{const f=e.target.files[0];if(f)setCommentMedia({file:f,type:'video',preview:URL.createObjectURL(f)});}}/>\n\n          <div style={{ display:'flex', gap:8, alignItems:'center' }}>\n            <button onClick={()=>cPhotoRef.current?.click()} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiPhotograph size={20}/></button>\n            <button onClick={()=>cVideoRef.current?.click()} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiVideoCamera size={20}/></button>\n            <input\n              placeholder={replyTo?`R\u00e9pondre \u00e0 ${replyTo}...`:\"\u00c9crire un commentaire...\"}\n              value={commentText} onChange={e=>setCommentText(e.target.value)}\n              onKeyDown={e=>e.key==='Enter'&&addComment(activePost.id)}\n              style={{ flex:1, background:'#050505', border:'1px solid #232733', borderRadius:25, padding:'9px 14px', color:'white', fontFamily:'Poppins', fontSize:13 }}\n            />\n            <button onClick={()=>addComment(activePost.id)} style={{ background:'#1877F2', border:'none', borderRadius:'50%', width:38, height:38, display:'flex', alignItems:'center', justifyContent:'center', cursor:'pointer', flexShrink:0 }}>\n              <span style={{ color:'white', fontSize:16 }}>\u27a4</span>\n            </button>\n          </div>\n        </div>\n      )}\n\n      {/* Edit comment modal */}\n      {editCmt&&(\n        <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.8)', zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div style={{ background:'#0B0D12', borderRadius:16, padding:20, width:'100%', maxWidth:360, border:'1px solid #232733' }}>\n            <h3 style={{ color:'white', marginBottom:12 }}>Modifier le commentaire</h3>\n            <textarea value={editCmt.text} onChange={e=>setEditCmt(p=>({...p,text:e.target.value}))} rows={3} style={{ width:'100%', background:'#050505', border:'1px solid #232733', borderRadius:10, padding:'8px 12px', color:'white', fontFamily:'Poppins', fontSize:13, resize:'none' }} maxLength={500}/>\n            <div style={{ display:'flex', gap:10, marginTop:12 }}>\n              <button onClick={()=>setEditCmt(null)} style={{ flex:1, background:'#050505', border:'1px solid #232733', borderRadius:20, padding:'9px', color:'#65676B', cursor:'pointer', fontFamily:'Poppins' }}>Annuler</button>\n              <button onClick={()=>saveEditCmt(activePost.id,editCmt.cmt,editCmt.text)} style={{ flex:1, background:'#1877F2', border:'none', borderRadius:20, padding:'9px', color:'white', cursor:'pointer', fontFamily:'Poppins', fontWeight:600 }}>Enregistrer</button>\n            </div>\n          </div>\n        </div>\n      )}\n\n      {/* Reaction modal */}\n      {reactionModal&&(\n        <div style={{ position:'absolute', inset:0, background:'rgba(0,0,0,0.8)', zIndex:200, display:'flex', alignItems:'center', justifyContent:'center', padding:20 }}>\n          <div style={{ background:'#0B0D12', borderRadius:16, padding:20, width:'100%', maxWidth:360, maxHeight:'70vh', overflowY:'auto', border:'1px solid #232733' }}>\n            <div style={{ display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:14 }}>\n              <h3 style={{ color:'white', fontWeight:700 }}>R\u00e9actions</h3>\n              <button onClick={()=>setRM(null)} style={{ background:'none', border:'none', cursor:'pointer', color:'#65676B' }}><HiX size={20}/></button>\n            </div>\n            {Object.entries(reactionModal.reactions).map(([uid,emoji])=>{\n              const info = reactionModal.userData?.[uid]||{};\n              return (\n                <div key={uid} onClick={()=>{setRM(null);navigate(`/profile/${uid}`);}} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 0', borderBottom:'1px solid #232733', cursor:'pointer' }}>\n                  <img src={info.photo||`https://ui-avatars.com/api/?name=${encodeURIComponent(info.name||'U')}&background=1877F2&color=fff`} alt=\"\" style={{ width:36, height:36, borderRadius:'50%', objectFit:'cover' }}/>\n                  <p style={{ fontSize:14, fontWeight:600, flex:1, color:'white' }}>{uid===currentUser.uid?'Vous':(info.name||uid)}</p>\n                  <span style={{ fontSize:20 }}>{emoji}</span>\n                </div>\n              );\n            })}\n          </div>\n        </div>\n      )}\n\n      {shareModal && <ShareModal post={shareModal} onClose={() => setShareModal(null)} />}\n      {boostTarget && <BoostOrderModal target={boostTarget} onClose={() => setBoostTarget(null)} />}\n    </div>\n  );\n}\n";

const fs = require('fs');
let OK = 0, SKIP = 0, FAIL = 0;
const ok = (m) => { OK++; console.log('OK ' + m); };
const skip = (m) => { SKIP++; console.log('SKIP ' + m); };
const fail = (m) => { FAIL++; console.log('FAIL ' + m); };

try {
  const p = 'src/index.css';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('overscroll-behavior-y: contain')) skip('index.css : overscroll deja corrige');
  else { fs.writeFileSync(p, CSS_SRC); ok('index.css : overscroll-behavior (fix pull-to-refresh natif)'); }
} catch (e) { fail('index.css: ' + e.message); }

try {
  const p = 'src/pages/Settings.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('BoostOrderModal')) skip('Settings.jsx : deja corrige');
  else { fs.writeFileSync(p, SETTINGS_SRC); ok('Settings.jsx : "Booster mon profil" -> formulaire (plus d\'email)'); }
} catch (e) { fail('Settings.jsx: ' + e.message); }

try {
  const p = 'src/pages/Reels.jsx';
  let s = fs.readFileSync(p, 'utf8');
  if (s.includes('BoostOrderModal')) skip('Reels.jsx : deja corrige');
  else { fs.writeFileSync(p, REELS_SRC); ok('Reels.jsx : bouton Boost -> formulaire (proprietaire)'); }
} catch (e) { fail('Reels.jsx: ' + e.message); }

console.log('\nRESUME: OK=' + OK + ' SKIP=' + SKIP + ' FAIL=' + FAIL);
